+package com.google.javascript.jscomp;
+
+import com.google.javascript.jscomp.CompilerOptions.LanguageMode;
+
+public final class TypeCheckNoTranspileTriggerTest extends TypeCheckTestCase {
+
+  @Override
+  protected CompilerOptions getDefaultOptions() {
+    CompilerOptions options = super.getDefaultOptions();
+    options.setLanguageIn(LanguageMode.ECMASCRIPT_NEXT);
+    options.setLanguageOut(LanguageMode.ECMASCRIPT_NEXT);
+    return options;
+  }
+
+  public void testDefaultParameterDropsUndefinedFromScopeType() {
+    testTypes(
+        lines(
+            "function f(/** number= */ n = 3) {",
+            "  var /** number */ x = n;",
+            "}"));
+  }
+}
